/**
 * @summary Trending hashtag rooms
 */
export const getGetTrendingRoomsUrl = (params?: GetTrendingRoomsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/rooms/trending?${stringifiedParams}`
    : `/api/rooms/trending`;
};

export const getTrendingRooms = async (
  params?: GetTrendingRoomsParams,
  options?: RequestInit,
): Promise<Room[]> => {
  return customFetch<Room[]>(getGetTrendingRoomsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetTrendingRoomsQueryKey = (
  params?: GetTrendingRoomsParams,
) => {
  return [`/api/rooms/trending`, ...(params ? [params] : [])] as const;
};

export const getGetTrendingRoomsQueryOptions = <
  TData = Awaited<ReturnType<typeof getTrendingRooms>>,
  TError = ErrorType<unknown>,
>(
  params?: GetTrendingRoomsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getTrendingRooms>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetTrendingRoomsQueryKey(params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getTrendingRooms>>
  > = ({ signal }) => getTrendingRooms(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getTrendingRooms>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetTrendingRoomsQueryResult = NonNullable<
  Awaited<ReturnType<typeof getTrendingRooms>>
>;
export type GetTrendingRoomsQueryError = ErrorType<unknown>;

/**
 * @summary Trending hashtag rooms
 */

export function useGetTrendingRooms<
  TData = Awaited<ReturnType<typeof getTrendingRooms>>,
  TError = ErrorType<unknown>,
>(
  params?: GetTrendingRoomsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getTrendingRooms>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetTrendingRoomsQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

/**
 * @summary List recent messages in a hashtag room
 */
export const getGetRoomMessagesUrl = (tag: string) => {
  return `/api/rooms/${tag}/messages`;
};

export const getRoomMessages = async (
  tag: string,
  options?: RequestInit,
): Promise<Message[]> => {
  return customFetch<Message[]>(getGetRoomMessagesUrl(tag), {
    ...options,
    method: "GET",
  });
};

export const getGetRoomMessagesQueryKey = (tag: string) => {
  return [`/api/rooms/${tag}/messages`] as const;
};

export const getGetRoomMessagesQueryOptions = <
  TData = Awaited<ReturnType<typeof getRoomMessages>>,
  TError = ErrorType<unknown>,
>(
  tag: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getRoomMessages>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetRoomMessagesQueryKey(tag);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getRoomMessages>>> = ({
    signal,
  }) => getRoomMessages(tag, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!tag,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getRoomMessages>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetRoomMessagesQueryResult = NonNullable<
  Awaited<ReturnType<typeof getRoomMessages>>
>;
export type GetRoomMessagesQueryError = ErrorType<unknown>;

/**
 * @summary List recent messages in a hashtag room
 */

export function useGetRoomMessages<
  TData = Awaited<ReturnType<typeof getRoomMessages>>,
  TError = ErrorType<unknown>,
>(
  tag: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getRoomMessages>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetRoomMessagesQueryOptions(tag, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

/**
 * @summary Post a message into a hashtag room
 */
export const getSendRoomMessageUrl = (tag: string) => {
  return `/api/rooms/${tag}/messages`;
};

export const sendRoomMessage = async (
  tag: string,
  sendMessageBody: SendMessageBody,
  options?: RequestInit,
): Promise<Message> => {
  return customFetch<Message>(getSendRoomMessageUrl(tag), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(sendMessageBody),
  });
};

export const getSendRoomMessageMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof sendRoomMessage>>,
    TError,
    { tag: string; data: BodyType<SendMessageBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof sendRoomMessage>>,
  TError,
  { tag: string; data: BodyType<SendMessageBody> },
  TContext
> => {
  const mutationKey = ["sendRoomMessage"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof sendRoomMessage>>,
    { tag: string; data: BodyType<SendMessageBody> }
  > = (props) => {
    const { tag, data } = props ?? {};

    return sendRoomMessage(tag, data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type SendRoomMessageMutationResult = NonNullable<
  Awaited<ReturnType<typeof sendRoomMessage>>
>;
export type SendRoomMessageMutationBody = BodyType<SendMessageBody>;
export type SendRoomMessageMutationError = ErrorType<unknown>;

/**
 * @summary Post a message into a hashtag room
 */
export const useSendRoomMessage = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof sendRoomMessage>>,
    TError,
    { tag: string; data: BodyType<SendMessageBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof sendRoomMessage>>,
  TError,
  { tag: string; data: BodyType<SendMessageBody> },
  TContext
> => {
  return useMutation(getSendRoomMessageMutationOptions(options));
};

